class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        vector<int> cnt(10, 0);
        for (int i = (1 << (n - 1)); i < (1 << n); i++) {
            string s = to_string(i);
            sort(s.begin(), s.end());
            do {
                int x = stoi(s);
                if (x % k == 0) cnt[x % 10]++;
            } while (next_permutation(s.begin(), s.end()));
        }
        long long res = 0;
        for (int i = 0; i < 10; i++) {
            res += (long long)cnt[i] * cnt[i];
        }
        return res;
    }
};
```
